head.script:
scwin.hid_kcomcd = "DBEX";

scwin.onpageload = function() {
    scwin.userId = $c.data.getMemInfo("userId");

    scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.strPreDate = $c.date.addDate(scwin.vCurDate, -7);

    ds_search.set("kcomcd", scwin.hid_kcomcd);

    scwin.f_set("INIT");
};

scwin.onUdcCompleted = function() {
    cnd_lc_send.setSelectedIndex(0);
    udc_fromToCalendar.setInitDate(scwin.strPreDate, scwin.vCurDate);
};

// 화면세팅
scwin.f_set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableBtnOnly([b_save]);
            gr_houseLicenseInfo.setReadOnly("grid", true);
            break;
        case "RETRIEVE":
            $c.gus.cfEnableKeyData(); // 실질적으로 적용되진 않지만, 기존과 동일하게 구현
            $c.gus.cfEnableBtnOnly([b_save]);
            break;
        // [CREATE | UPDATE | SAVE | DELETE] 호출하는 경우는 없지만, 기존과 동일하게 구현 및 주석처리
        // case "CREATE":
        //     $c.gus.cfDisableKey();
        //     scwin.f_EnablePopUpObj();
        //     $c.gus.cfDisableBtnOnly([b_Create, b_Update, b_Delete]);
        //     $c.gus.cfEnableBtnOnly([b_save, b_Cancel]);
        //     break;
        // case "UPDATE":
        //     $c.gus.cfDisableBtnOnly([b_Update, b_Create]);
        //     $c.gus.cfEnableBtnOnly([b_save, b_Delete, b_Cancel]);
        //     $c.gus.cfDisableKey();
        //     scwin.f_EnablePopUpObj();
        //     break;
        // case "SAVE":
        //     $c.gus.cfDisableBtnOnly([b_save, b_Delete, b_Cancel]);
        //     $c.gus.cfEnableBtnOnly([b_Update, b_Create]);
        //     break;
        // case "DELETE":
        //     $c.gus.cfDisableBtnOnly([b_save, b_Delete, b_Cancel]);
        //     $c.gus.cfEnableBtnOnly([b_Create, b_Update]);
        //     break;
    }
};

//---------------------------------------------------------
// Master Information 조회 
//---------------------------------------------------------     
scwin.f_Retrieve = async function() {
    let rtn = await $c.gus.cfValidate([cnd_ed_ondtFrom, cnd_ed_ondtTo]);
    if (!rtn) {
        return false;
    }

    if (!$c.gus.cfIsAfterDate(cnd_ed_ondtFrom.getValue().trim(), cnd_ed_ondtTo.getValue().trim(), false)) {
        $c.win.alert($c.data.getMessage(E_MSG_CM_ERR_039)); // Start date must be before End date.
        return;
    }

    ds_search.set("kcomcd", scwin.hid_kcomcd);

    await $c.sbm.execute(sbm_retrieve);
};

//---------------------------------------------------------
// License Information 조회 
//---------------------------------------------------------   
scwin.f_retrieveHouseLicenseInfo = async function(row) {
    ds_search.set("kcomcd", ds_exportMaster.getCellData(row, "kcomcd"));
    // ds_search.set("blno", ds_exportMaster.getCellData(row, "blno"));
    ds_search.set("mhno", ds_exportMaster.getCellData(row, "mhno"));

    await $c.sbm.execute(sbm_houseLicenseInfo);
};

//---------------------------------------------------------
// 저장(EDI Send)
//--------------------------------------------------------- 
scwin.f_save = async function() {
    let chk = await scwin.f_reqFieldChk();
    if (!chk) return;

    let vChkCnt = 0;
    for (let i = 0; i < ds_exportMaster.getRowCount(); i++) {
        let vChkYn  = ds_exportMaster.getCellData(i, "chk");
        let vMftpkg = ds_exportMaster.getCellData(i, "mftpkg");
        let vExnoCnt = ds_exportMaster.getCellData(i, "exnoCnt");

        let vSendDt = ds_exportMaster.getCellData(i, "sendDt");

        if (vChkYn == "T") {
            if (vMftpkg < 1) {
                $c.win.alert($c.data.getMessage(MSG_CM_ERR_013, "항공수출 적하목록에 "+(i+1)+"째 데이터에서 Packag", "1"));
                return;
            }

            ds_exportMaster.setCellData(i, "updid", scwin.userId);

            // 기존 sendDt에 따라 나뉜 분기는 하나로 통합
            ds_exportMaster.modifyRowStatus(i, "C"); // 서버단 처리시 INSERT행 처리 위해 상태값 "C"로 변경

            vChkCnt++;
        }

        // AS-IS: vChkYn 분기 이전에 updid(=userId)를 모든 행에 세팅하여 rowStatus가 변경되는 부작용이 있었음
        // TO-BE: chk=="T"인 행에만 updid 세팅 및 rowStatus "C" 변경으로 수정하여 불필요한 상태 변경 제거
        // if (vChkYn == "F") {
        //     ds_exportMaster.modifyRowStatus(i, "R");
        // }
    }

    if (vChkCnt < 1) {
        $c.win.alert($c.data.getMessage(E_MSG_CM_ERR_056, "Row")); // No @ has been selected.
        return;
    }

    await $c.sbm.execute(sbm_save);
};

//---------------------------------------------------------
// 유효성 검사
//---------------------------------------------------------   
scwin.f_reqFieldChk = async function() {
    let chk = await $c.gus.cfValidate([gr_exportMaster]);
    if (!chk) {
        return false;
    }
    return true;
};

//---------------------------------------------------------
// 특수기호 문자를 입력 받지않는 함수
// - AS-IS와 동일하게 구현하였으나, 이 페이지는 그리드가 ReadOnly이므로 실질적으로 동작하지 않음
//---------------------------------------------------------
scwin.f_ChkKeyCode = function(ds, row, colid) {
    try {
        let str = ds.getCellData(row, colid);
        let chkStr = "";
        let comStr = "";
        let badStr = "";
        for (let i = 0; i < str.length; i++) {
            chkStr = str.charCodeAt(i);
            if ((chkStr >= 33) && (chkStr <= 39)) {
                badStr += str.charAt(i);
            } else if ((chkStr >= 91) && (chkStr <= 96)) {
                badStr += str.charAt(i);
            } else if ((chkStr >= 123) && (chkStr <= 126)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 63)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 64)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 43)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 59)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 0)) {
                badStr += str.charAt(i);
            } else {
                comStr += str.charAt(i);
            }
        }
        ds.setCellData(row, colid, comStr);
    } catch (e) {
    }
};

///////////////////////////////////////////// S U B M I S S I O N    E V E N T /////////////////////////////////////////

// Master Information 조회
scwin.sbm_retrieve_submitdone = function(e) {
    if (ds_exportMaster.getRowCount() == 0) {
        $c.win.alert($c.data.getMessage(E_MSG_CM_WRN_002));
    }
    totalRowsExportMaster.setValue(ds_exportMaster.getRowCount());

    scwin.f_set("RETRIEVE");
};

// License Information 조회
scwin.sbm_houseLicenseInfo_submitdone = function(e) {
    totalRowsHouseLicenseInfo.setValue(ds_houseLicenseInfo.getRowCount());
};

// 저장(EDI Send)
scwin.sbm_save_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code >= 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_INF_001)); // 성공적으로 저장하였습니다.
    }

    scwin.f_Retrieve();
};

///////////////////////////////////////////// C O M P O N E N T   E V E N T /////////////////////////////////////////

// 조회조건 초기화
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tb_searchCondition);
};

// Save(EDI Send) 버튼 onClick
scwin.b_save_onclick = function(e) {
    scwin.f_save();
};

// Master Information 그리드 행 선택시
scwin.gr_exportMaster_oncellclick = function(rowIndex, columnIndex, columnId) {
    scwin.f_retrieveHouseLicenseInfo(rowIndex);
};

// DataSet ds_exportMaster, ds_houseLicenseInfo onCellDataChange
//  - ds_exportMaster, ds_houseLicenseInfo 의 oncelldatachange 이벤트는 기존과 동일하게 구현
//  - 단, gr_houseLicenseInfo는 INIT 시 ReadOnly로 설정되어 실질적으로 동작하지 않음
scwin.ds_exportMaster_oncelldatachange = function(info) {
    scwin.f_ChkKeyCode(ds_exportMaster, info.row, info.colId);
};

scwin.ds_houseLicenseInfo_oncelldatachange = function(info) {
    scwin.f_ChkKeyCode(ds_houseLicenseInfo, info.row, info.colId);
};

// Flight No 대문자
scwin.cnd_ed_fltno_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

// Master B/L No 대문자
scwin.cnd_ed_mblno_onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

// KT Net 접속 버튼
scwin.btn_KtNetOpen_onclick = function (e) {
    let sURL = "http://www.ctradeworld.com/ctwpass/userLoginChk.jsp?userid=FFDBEX0001&userpass=DBE123";
    window.open(sURL);
};

// uLogishub 접속 버튼
scwin.btn_uLogisHubOpen_onclick = function (e) {
    let sURL = "https://www.ulogishub.com/gate_url.jsp?sid=FFDBEX0001&password=DBE123";
    window.open(sURL);
};
